    16|use Shopware5Bundle\Shopware5;
    17|
    18|class OrderEnricher
    19|{
    20|    /**
    21|     * @var AkeneoService
    22|     */
    23|    private $akeneoService;
    24|
    25|    public function __construct(AkeneoService $akeneoService)
    26|    {
    27|        $this->akeneoService = $akeneoService;
    28|    }
    29|
    30|    /**
    31|     * @param RawOrder $rawOrder
    32|     *
    33|     * @return EnrichedOrder
    34|     *
    35|     * @throws Exception
    36|     */
    37|    public function getEnrichedOrder(RawOrder $rawOrder): EnrichedOrder
    38|    {
    39|        $enrichedOrder = new EnrichedOrder();
    40|
    41|        /** @var RawOrderItem $rawOrderItem */
    42|        foreach ($rawOrder->getOrderItems() as $rawOrderItem) {
    43|            $enrichedOrderItem = new EnrichedOrderItem();
    44|
    45|            $akeneoBaseVariant = $this->akeneoService->getProduct($rawOrderItem->getBaseProductSKU());
    46|
    47|            $enrichedOrderItem->setAkeneoBaseVariant($akeneoBaseVariant);
    48|            $enrichedOrderItem->setId($rawOrderItem->getId());
    49|            $enrichedOrderItem->setArticleNumber($rawOrderItem->getArticleNumber());
    50|            $enrichedOrderItem->setQuantity($rawOrderItem->getQuantity());
    51|            $enrichedOrderItem->setPreviewImageURL($this->unsecureUrl($rawOrderItem->getPreviewImageURL()));
    52|            $enrichedOrderItem->setDesignImageURL($this->unsecureUrl($rawOrderItem->getDesignImageURL()));
    53|            $enrichedOrderItem->setComposition($this->getCompositionModelFromOrderItem($rawOrderItem));
    54|            $enrichedOrderItem->setNetPrice($rawOrderItem->getNetPrice());
    55|
    56|            $enrichedOrder->addOrderItem($enrichedOrderItem);
    57|        }
    58|
    59|        $shipping = new Shipping();
    60|
    61|        if (null !== $rawOrder->getShipping()->getCompany()) {
    62|            $shipping->setCompany($rawOrder->getShipping()->getCompany());
    63|        }
    64|
    65|        $shipping->setFirstName($rawOrder->getShipping()->getFirstName());
    66|        $shipping->setLastName($rawOrder->getShipping()->getLastName());
    67|        $shipping->setStreet($rawOrder->getShipping()->getStreet());
    68|        $shipping->setAddressLine1($rawOrder->getShipping()->getAddressLine1());
    69|        $shipping->setAddressLine2($rawOrder->getShipping()->getAddressLine2());
    70|        $shipping->setZipCode($rawOrder->getShipping()->getZipCode());
    71|        $shipping->setCity($rawOrder->getShipping()->getCity());
    72|        $shipping->setCountry($rawOrder->getShipping()->getCountry());
    73|        $shipping->setPhone($rawOrder->getShipping()->getPhone());
    74|        $shipping->setEmail($rawOrder->getShipping()->getEmail());
    75|        $shipping->setIsExpress($rawOrder->getShipping()->isExpress());
    76|        $shipping->setShippingLabel($rawOrder->getShipping()->getShippingLabelUrl());
    77|        $shipping->setExportDocument($rawOrder->getShipping()->getExportDocumentUrl());
    78|        $shipping->setOptigerCarrierId($rawOrder->getShipping()->getOptigerCarrierId());
    79|
    80|        $enrichedOrder->setShipping($shipping);
    81|        $enrichedOrder->setPartnerId($rawOrder->getPartnerId());
    82|        $enrichedOrder->setOrderNumber($rawOrder->getOrderNumber());
    83|        $enrichedOrder->setOrderType($rawOrder->getOrderType());
    84|        $enrichedOrder->setOrderTime($rawOrder->getOrderTime());
    85|        $enrichedOrder->setSource(Shopware5::NAME);
    86|        $enrichedOrder->setCurrency($rawOrder->getCurrency());
    87|        $enrichedOrder->setRequiredPrintProvider($rawOrder->getRequiredPrintProvider());
    88|        $enrichedOrder->setInvoice($rawOrder->getShipping()->getZollRechnungUrl());
