    98|    public function getEnrichedOrderStatus(RawOrderStatus $rawOrderStatus): EnrichedOrderStatus
    99|    {
   100|        $enrichedOrderStatus = new EnrichedOrderStatus();
   101|        $enrichedOrderStatus->setOrderId($rawOrderStatus->getOrderId());
   102|        $enrichedOrderStatus->setSource($rawOrderStatus->getSource());
   103|        $enrichedOrderStatus->setState($rawOrderStatus->getState());
   104|        $enrichedOrderStatus->setPrintProvider($rawOrderStatus->getPrintProvider());
   105|        $enrichedOrderStatus->setPrintProviderReference($rawOrderStatus->getPrintProviderReference());
   106|
   107|        return $enrichedOrderStatus;
