{"content": "     1|<?php
     2|
     3|namespace AppBundle\MessageHandler;
     4|
     5|use AppBundle\Message\OrderNotification;
     6|use Shirtinator\OrderFulfillment\Messages\OrderItem;
     7|use Shirtinator\OrderFulfillment\Messages\OrderStatusUpdate;
     8|use AppBundle\Service\OrderEnricher;
     9|use AppBundle\Service\OrderRouter;
    10|use AppBundle\Service\StatusUpdateService;
    11|use Psr\Log\LoggerInterface;
    12|use Shopware5Bundle\ShippingDocumentAdder;
    13|use Symfony\Component\HttpFoundation\Response;
    14|use Symfony\Component\Messenger\Handler\MessageHandlerInterface;
    15|use Symfony\Component\Messenger\MessageBusInterface;
    16|
    17|class OrderHandler implements MessageHandlerInterface
    18|{
    19|    private OrderRouter $orderRouter;
    20|
    21|    private LoggerInterface $logger;
    22|
    23|    private OrderEnricher $orderEnricher;
    24|
    25|    private StatusUpdateService $statusUpdateService;
    26|
    27|    private MessageBusInterface $messageBus;
    28|    private ShippingDocumentAdder $shopwareShippingDocumentAdder;
    29|
    30|    public function __construct(
    31|        OrderRouter $orderRouter,
    32|        LoggerInterface $logger,
    33|        OrderEnricher $orderEnricher,
    34|        StatusUpdateService $statusUpdateService,
    35|        MessageBusInterface $messageBus,
    36|        ShippingDocumentAdder $shopwareShippingDocumentAdder,
    37|    ) {
    38|        $this->orderRouter                   = $orderRouter;
    39|        $this->logger                        = $logger;
    40|        $this->orderEnricher                 = $orderEnricher;
    41|        $this->statusUpdateService           = $statusUpdateService;
    42|        $this->messageBus                    = $messageBus;
    43|        $this->shopwareShippingDocumentAdder = $shopwareShippingDocumentAdder;
    44|    }
    45|
    46|    public function __invoke(OrderNotification $notification)
    47|    {
    48|        $order = $notification->getOrder();
    49|        try {
    50|            if (null === $order->getOrderSource() || 'shopware' === $order->getOrderSource()) {
    51|                $this->shopwareShippingDocumentAdder->process($order);
    52|            }
    53|
    54|            $ofeInternalOrder = $this->orderEnricher->getEnrichedOrder($order);
    55|
    56|            $result = $this->orderRouter->processOrder($ofeInternalOrder);
    57|
    58|            $status = new OrderStatusUpdate($order->getOrderNumber(), $result->getState());
    59|            $status->printProvider = $result->getProduction();
    60|            $status->printProviderReference = $result->getPrintProviderReferenceNumber();
    61|            $status->printProviderStatus = 'New';
    62|
    63|            foreach ($result->getPrintData() as $orderItemId => $printData) {
    64|                $item = new OrderItem((string) $orderItemId);
    65|                $item->printProviderSKU = isset($printData['sku']) ? (string) $printData['sku'] : null;
    66|                $item->printDataFiles = isset($printData['files']) && is_array($printData['files']) ? $printData['files'] : [];
    67|                $status->orderItems[] = $item;
    68|            }
    69|
    70|            $this->statusUpdateService->sendOrderStatusUpdate($order->getOrderSource(), $status);
    71|        } catch (\Throwable $exception) {
    72|            $this->logger->critical(
    73|                sprintf('[%s] Order creation failed', $order->getOrderNumber()),
    74|                [
    75|                    'code'      => $exception->getCode(),
    76|                    'message'   => $exception->getMessage(),
    77|                    'exception' => $exception->getTraceAsString(),
    78|                ]
    79|            );
    80|
    81|            if (Response::HTTP_BAD_GATEWAY === $exception->getCode()) {
    82|                $this->logger->info(sprintf('[%s] Bad Gateway. Retry next time', $order->getOrderNumber()));
    83|
    84|                return;
    85|            }
    86|
    87|            // Retry order failed by curl timeouts
    88|            // SS-5890 https://shirtinator.atlassian.net/browse/SS-5890
    89|            if (false !== stripos($exception->getMessage(), 'cURL error 28: Operation timed out') && !$notification->isRetry()) {
    90|                // This is the first time this message is being processed and failed, requeue for reprocessing one more time
    91|                $this->logger->info(sprintf('[%s] Requeuing order', $order->getOrderNumber()));
    92|                $this->messageBus->dispatch($notification->setRetry());
    93|
    94|                return;
    95|            }
    96|
    97|            $this->logger->info(sprintf('[%s] Setting order status to Klarung notwendig', $order->getOrderNumber()));
    98|
    99|            $status = new OrderStatusUpdate($order->getOrderNumber(), OrderStatusUpdate::STATUS_CLARIFICATION_REQUIRED);
   100|            $status->errorMessage = 'Technical issue: ' . $exception->getMessage();
   101|
   102|            $this->statusUpdateService->sendOrderStatusUpdate($order->getOrderSource(), $status);
   103|        }
   104|    }
   105|}
