{"content": "     1|<?php
     2|
     3|namespace Shopware5Bundle;
     4|
     5|use AppBundle\Model\CN23StickeredExportDocument;
     6|use AppBundle\Model\Document;
     7|use AppBundle\Service\FileService;
     8|use Psr\Log\LoggerAwareTrait;
     9|use Shirtinator\OrderFulfillment\Dto\Order;
    10|use Shirtinator\Shopware\Client;
    11|
    12|class ShippingDocumentAdder
    13|{
    14|    use LoggerAwareTrait;
    15|
    16|    private Client $shopwareClient;
    17|
    18|    /** @var FileService */
    19|    private $fileService;
    20|
    21|    public function __construct(Client $shopwareClient, FileService $fileService)
    22|    {
    23|        $this->shopwareClient = $shopwareClient;
    24|        $this->fileService = $fileService;
    25|    }
    26|
    27|    public function process(Order $order): void
    28|    {
    29|        $orderNumber = $order->getOrderNumber();
    30|        $documentApi = $this->shopwareClient->getDocumentApi();
    31|
    32|        $this->addShippingLabel($order);
    33|        $this->addExportDocument($order);
    34|        $this->addInvoice($order);
    35|    }
    36|
    37|    private function addShippingLabel(Order $order)
    38|    {
    39|        $shippingLabel = $this->shopwareClient->getDocumentApi()->getDocument(
    40|            $order->getOrderNumber(),
    41|            'shippinglabel',
    42|            'Shipping Label'
    43|        );
    44|
    45|        if (!$shippingLabel->exists()) {
    46|            return;
    47|        }
    48|
    49|        $shippingLabelFileContent = $shippingLabel->getDocument();
    50|        $shippingLabelProduct = $this->shopwareClient->getDocumentApi()->getShippingLabelProduct($order->getOrderNumber());
    51|        $shippingProviderCode = $shippingLabelProduct->getStrategy();
    52|
    53|        $shippingLabelUrl = $this->storeFile(
    54|            $shippingLabelFileContent,
    55|            $order->getOrderNumber(),
    56|            FileService::FILE_TYPE_SHIPPING_LABEL
    57|        );
    58|
    59|        $order->getShipping()->setShippingLabelUrl($shippingLabelUrl);
    60|        $order->getShipping()->setShippingProvider($shippingProviderCode);
    61|    }
    62|
    63|    private function addExportDocument(Order $order)
    64|    {
    65|        $export = $this->shopwareClient->getDocumentApi()->getDocument(
    66|            $order->getOrderNumber(),
    67|            'shippingexportdocument',
    68|            'Export Document'
    69|        );
    70|
    71|        if ('CH' === $order->getShipping()->getCountry() && !$export->exists()) {
    72|            $message = sprintf(
    73|                '[%s] Export document for order is not available',
    74|                $order->getOrderNumber()
    75|            );
    76|
    77|            $this->logger->error($message);
    78|
    79|            throw new \Exception($message);
    80|        }
    81|
    82|        if (!$export->exists()) {
    83|            return;
    84|        }
    85|
    86|        $exportDocumentFileContent = $export->getDocument();
    87|
    88|        if ('CH' === $order->getShipping()->getCountry()) {
    89|            $cn23Stickered = new CN23StickeredExportDocument(
    90|                (new Document())->setDocument($exportDocumentFileContent)
    91|            );
    92|            $exportDocumentFileContent = $cn23Stickered->getDocument();
    93|        }
    94|
    95|        $exportDocumentUrl = $this->storeFile(
    96|            $exportDocumentFileContent,
    97|            $order->getOrderNumber(),
    98|            FileService::FILE_TYPE_ATTACHMENT,
    99|            '-export-document'
   100|        );
   101|        $order->getShipping()->setExportDocumentUrl($exportDocumentUrl);
   102|    }
   103|
   104|    private function addInvoice(Order $order)
   105|    {
   106|        if ('CH' !== $order->getShipping()->getCountry()) {
   107|            return;
   108|        }
   109|
   110|        $invoice = $this->shopwareClient->getDocumentApi()->getDocument(
   111|            $order->getOrderNumber(),
   112|            'invoice-einzelverzollung',
   113|            'Einzelverzollung Invoice'
   114|        );
   115|
   116|        if (!$invoice->exists()) {
   117|            $message = sprintf(
   118|                '[%s] Invoice for order is not available',
   119|                $order->getOrderNumber()
   120|            );
   121|
   122|            $this->logger->error($message);
   123|
   124|            throw new \Exception($message);
   125|        }
   126|
