    31|
    32|    /**
    33|     * @param OrderRouter $orderRouter
    34|     * @param LoggerInterface $logger
    35|     * @param MessageBusInterface $messageBus
    36|     */
    37|    public function __construct(
    38|        OrderRouter $orderRouter,
    39|        LoggerInterface $logger,
    40|        MessageBusInterface $messageBus,
    41|    ) {
    42|        $this->orderRouter = $orderRouter;
    43|        $this->logger = $logger;
    44|        $this->messageBus = $messageBus;
    45|    }
    46|
    47|    /**
    48|     * @Route("/orders", methods={"POST"}, )
    49|     *
    50|     * @param OrderDTO $order
    51|     *
    52|     * @return JsonResponse
    53|     */
    54|    public function postOrder(OrderDTO $order): JsonResponse
    55|    {
    56|        $status = Response::HTTP_OK;
    57|        $result = new OrderProcessingResult();
    58|
    59|        try {
    60|            $orderNotification = new OrderNotification($order);
    61|            $this->messageBus->dispatch($orderNotification);
    62|
    63|            $result->setSuccess(true);
    64|        } catch (Throwable $exception) {
    65|            $this->logger->critical($exception->getMessage(), [
    66|                'order'     => $order->getOrderNumber(),
    67|                'exception' => $exception,
    68|            ]);
    69|
    70|            $result->setSuccess(false);
    71|            $result->setMessage($exception->getMessage());
    72|            $status = Response::HTTP_INTERNAL_SERVER_ERROR;
    73|        }
    74|
    75|        return new JsonResponse($result, $status);
    76|    }
    77|
    78|    /**
    79|     * @Route("/order-status", methods={"POST"})
    80|     *
    81|     * @param OrderStatusCollection $orders
    82|     *
    83|     * @return JsonResponse
    84|     */
    85|    public function postOrderStatus(OrderStatusCollection $orders): JsonResponse
    86|    {
    87|        $result     = new OrderProcessingResult();
    88|        $httpStatus = 200;
    89|
    90|        try {
    91|            foreach ($orders->getOrderStatusItems() as $statusItem) {
    92|                $this->messageBus->dispatch((new OrderStatusNotification($statusItem)));
    93|            }
    94|
    95|            $result->setSuccess(true);
    96|        } catch (Throwable $exception) {
    97|            $this->logger->critical($exception->getMessage(), [
    98|                'orders'    => $orders->getOrderStatusItems(),
    99|                'exception' => $exception,
   100|            ]);
   101|
   102|            $result->setSuccess(false);
   103|            $result->setMessage($exception->getMessage());
   104|            $httpStatus = 500;
   105|        }
   106|
   107|        return new JsonResponse($result, $httpStatus);
   108|    }
   109|
   110|    /**
   111|     * @Route("/orders/{printProvider}/{externalReference}", methods={"DELETE"})
   112|     *
   113|     * @param string $printProvider
   114|     * @param string $externalReference
   115|     *
   116|     * @return JsonResponse
   117|     */
   118|    public function cancelOrder(string $printProvider, string $externalReference): JsonResponse
