   130|
   131|            $result = new OrderProcessingResult();
   132|            $result->setSuccess(false);
   133|            $result->setMessage($exception->getMessage());
   134|            $status = 500;
   135|        }
   136|
   137|        return new JsonResponse($result, $status);
